import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { messagesAPI, authAPI } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { format, isToday, isYesterday, isSameDay } from 'date-fns';
import toast from 'react-hot-toast';
import TaskQuickPopup from '../Tasks/TaskQuickPopup';

// Add CSS animations
const style = document.createElement('style');
style.textContent = `
  @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
  }
  @keyframes typing {
    0%, 60%, 100% { transform: translateY(0); }
    30% { transform: translateY(-10px); }
  }
`;
document.head.appendChild(style);

/* ── Professional Color Palette & Design System ─────────────────────────────────── */
const DESIGN_SYSTEM = {
  colors: {
    primary: '#0084ff',
    primaryDark: '#0066cc',
    primaryLight: '#e6f3ff',
    secondary: '#f0f2f5',
    background: '#ffffff',
    backgroundDark: '#1a1a1a',
    surface: '#ffffff',
    surfaceDark: '#2a2a2a',
    text: '#111b21',
    textDark: '#e9edef',
    textSecondary: '#667781',
    textSecondaryDark: '#8696a0',
    border: '#e9edef',
    borderDark: '#2a2a2a',
    ownMessage: '#dcf8c6',
    ownMessageDark: '#005c4b',
    accent: '#25d366',
    danger: '#ff3b30',
    warning: '#ff9500',
    success: '#34c759'
  },
  spacing: {
    xs: '4px',
    sm: '8px',
    md: '16px',
    lg: '24px',
    xl: '32px',
    xxl: '48px'
  },
  borderRadius: {
    sm: '6px',
    md: '12px',
    lg: '18px',
    xl: '24px',
    full: '50%'
  },
  shadows: {
    sm: '0 1px 2px rgba(0, 0, 0, 0.05)',
    md: '0 4px 6px rgba(0, 0, 0, 0.07)',
    lg: '0 10px 15px rgba(0, 0, 0, 0.1)',
    xl: '0 20px 25px rgba(0, 0, 0, 0.1)'
  }
};

const AVATAR_COLORS = [
  '#ff6b6b', '#4ecdc4', '#45b7d1', '#96ceb4', '#feca57',
  '#ff9ff3', '#54a0ff', '#48dbfb', '#00d2d3', '#5f27cd'
];

function getAvatarColor(name) {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

function getInitials(name) {
  return name.split(' ').map(word => word[0]).join('').toUpperCase().slice(0, 2);
}

function formatDate(date) {
  const dt = new Date(date);
  if (isToday(dt)) return 'Today';
  if (isYesterday(dt)) return 'Yesterday';
  return format(dt, 'MMMM d, yyyy');
}

function formatTime(date) {
  return format(new Date(date), 'HH:mm');
}

function formatFileSize(bytes) {
  if (!bytes) return '';
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / 1048576).toFixed(1) + ' MB';
}

function getFileIcon(mimeType) {
  if (!mimeType) return '📄';
  if (mimeType.startsWith('image/')) return '🖼️';
  if (mimeType.startsWith('audio/')) return '🎵';
  if (mimeType.includes('pdf')) return '📕';
  if (mimeType.includes('sheet') || mimeType.includes('excel') || mimeType.includes('csv')) return '📊';
  if (mimeType.includes('word')) return '📝';
  if (mimeType.includes('zip')) return '🗜️';
  return '📎';
}

/* ── Professional Task Pill Component ─────────────────────────────────── */
const TASK_TYPES = {
  initial_setup: { icon: '🚀', color: '#a855f7', label: 'Setup' },
  share_link: { icon: '🔗', color: '#0084ff', label: 'Share' },
  pause_pid: { icon: '⏸️', color: '#ff9500', label: 'Pause' },
  raise_request: { icon: '📋', color: '#34c759', label: 'Request' },
  optimise: { icon: '⚡', color: '#00d2d3', label: 'Optimize' }
};

function TaskPill({ taskRef, onTaskClick }) {
  if (!taskRef) return null;
  const taskType = TASK_TYPES[taskRef.task_type] || TASK_TYPES.share_link;

  return (
    <div 
      onClick={() => onTaskClick?.(taskRef.task_id, taskRef.task_type)}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: DESIGN_SYSTEM.spacing.sm,
        background: `${taskType.color}15`,
        border: `1px solid ${taskType.color}30`,
        borderRadius: DESIGN_SYSTEM.borderRadius.lg,
        padding: `${DESIGN_SYSTEM.spacing.xs} ${DESIGN_SYSTEM.spacing.sm}`,
        cursor: 'pointer',
        fontSize: '12px',
        color: taskType.color,
        fontWeight: '600',
        marginTop: DESIGN_SYSTEM.spacing.sm,
        userSelect: 'none',
        transition: 'all 0.2s ease',
        boxShadow: DESIGN_SYSTEM.shadows.sm
      }}
      onMouseEnter={e => {
        e.currentTarget.style.background = `${taskType.color}25`;
        e.currentTarget.style.transform = 'translateY(-1px)';
        e.currentTarget.style.boxShadow = DESIGN_SYSTEM.shadows.md;
      }}
      onMouseLeave={e => {
        e.currentTarget.style.background = `${taskType.color}15`;
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = DESIGN_SYSTEM.shadows.sm;
      }}
    >
      <span style={{ fontSize: '14px' }}>{taskType.icon}</span>
      <span>{taskRef.task_title}</span>
      <span style={{ fontSize: '10px', opacity: 0.7 }}>→</span>
    </div>
  );
}

/* ── Professional Message Bubble Component ───────────────────────────── */
function Bubble({ msg, isOwn, showAvatar, onTaskClick, group }) {
  const { user } = useAuth();
  const [showOptions, setShowOptions] = useState(false);
  const [localReactions, setLocalReactions] = useState(msg.reactions || []);
  const messageRef = useRef(null);

  const handleCopy = async () => {
    let textToCopy = '';
    if (msg.content) {
      textToCopy = msg.content;
    } else if (msg.file_name) {
      textToCopy = msg.file_name;
    }

    try {
      await navigator.clipboard.writeText(textToCopy);
      toast.success('Message copied');
    } catch (error) {
      toast.error('Failed to copy');
    }
  };

  const handleForward = () => {
    const forwardData = {
      content: msg.content,
      file_url: msg.file_url,
      file_name: msg.file_name,
      message_type: msg.message_type
    };
    localStorage.setItem('forwardMessage', JSON.stringify(forwardData));
    toast.success('Message ready to forward');
  };

  const handleReact = async (reaction) => {
    try {
      const response = await messagesAPI.addReaction(group.id, msg.id, reaction);
      setLocalReactions(response.reactions);
      toast.success(`Reacted with ${reaction}`);
    } catch (error) {
      toast.error('Failed to add reaction');
    }
  };

  const handleDelete = async () => {
    try {
      await messagesAPI.deleteMessage(group.id, msg.id);
      toast.success('Message deleted');
    } catch (error) {
      toast.error('Failed to delete message');
    }
  };

  // System and task notification messages
  if (msg.message_type === 'task_notification' || msg.message_type === 'system') {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        padding: DESIGN_SYSTEM.spacing.sm,
        margin: `${DESIGN_SYSTEM.spacing.md} 0`
      }}>
        <div style={{
          background: DESIGN_SYSTEM.colors.primaryLight,
          border: `1px solid ${DESIGN_SYSTEM.colors.primary}30`,
          borderRadius: DESIGN_SYSTEM.borderRadius.xl,
          padding: `${DESIGN_SYSTEM.spacing.sm} ${DESIGN_SYSTEM.spacing.lg}`,
          fontSize: '13px',
          color: DESIGN_SYSTEM.colors.primary,
          fontWeight: '500',
          display: 'inline-flex',
          alignItems: 'center',
          gap: DESIGN_SYSTEM.spacing.sm,
          maxWidth: '80%',
          boxShadow: DESIGN_SYSTEM.shadows.sm
        }}>
          <span>{msg.content}</span>
          {msg.task_ref && <TaskPill taskRef={msg.task_ref} onTaskClick={onTaskClick} />}
        </div>
      </div>
    );
  }

  const fileUrl = msg.file_url || null;

  return (
    <div 
      style={{
        display: 'flex',
        flexDirection: isOwn ? 'row-reverse' : 'row',
        alignItems: 'flex-end',
        gap: DESIGN_SYSTEM.spacing.sm,
        marginBottom: DESIGN_SYSTEM.spacing.sm,
        position: 'relative'
      }}
    >
      {/* Avatar */}
      {!isOwn && (
        <div style={{
          width: '40px',
          height: '40px',
          borderRadius: DESIGN_SYSTEM.borderRadius.full,
          background: getAvatarColor(msg.sender_name),
          color: '#ffffff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: '14px',
          fontWeight: '700',
          flexShrink: 0,
          opacity: showAvatar ? 1 : 0,
          transition: 'opacity 0.2s ease',
          boxShadow: DESIGN_SYSTEM.shadows.sm
        }}>
          {showAvatar ? getInitials(msg.sender_name) : ''}
        </div>
      )}

      {/* Message Content */}
      <div style={{
        maxWidth: '70%',
        display: 'flex',
        flexDirection: 'column',
        alignItems: isOwn ? 'flex-end' : 'flex-start'
      }}>
        {/* Sender Name */}
        {showAvatar && !isOwn && (
          <div style={{
            fontSize: '13px',
            fontWeight: '600',
            color: DESIGN_SYSTEM.colors.textSecondary,
            marginBottom: DESIGN_SYSTEM.spacing.xs,
            paddingLeft: DESIGN_SYSTEM.spacing.sm
          }}>
            {msg.sender_name}
            <span style={{
              fontSize: '11px',
              color: DESIGN_SYSTEM.colors.textSecondary,
              fontWeight: '400',
              marginLeft: DESIGN_SYSTEM.spacing.xs,
              textTransform: 'capitalize'
            }}>
              [{msg.sender_role}]
            </span>
          </div>
        )}

        {/* Reply Preview */}
        {msg.reply_content && (
          <div style={{
            background: DESIGN_SYSTEM.colors.secondary,
            borderLeft: `3px solid ${DESIGN_SYSTEM.colors.primary}`,
            borderRadius: DESIGN_SYSTEM.borderRadius.sm,
            padding: DESIGN_SYSTEM.spacing.sm,
            marginBottom: DESIGN_SYSTEM.spacing.xs,
            fontSize: '12px',
            color: DESIGN_SYSTEM.colors.textSecondary,
            maxWidth: '100%'
          }}>
            <strong>{msg.reply_sender_name}: </strong>
            {msg.reply_content?.slice(0, 80)}
            {msg.reply_content?.length > 80 && '…'}
          </div>
        )}

        {/* Message Bubble */}
        <div style={{
          background: isOwn ? DESIGN_SYSTEM.colors.ownMessage : DESIGN_SYSTEM.colors.surface,
          borderRadius: DESIGN_SYSTEM.borderRadius.md,
          borderBottomLeftRadius: !isOwn ? '4px' : DESIGN_SYSTEM.borderRadius.md,
          borderBottomRightRadius: isOwn ? '4px' : DESIGN_SYSTEM.borderRadius.md,
          boxShadow: DESIGN_SYSTEM.shadows.sm,
          padding: DESIGN_SYSTEM.spacing.sm,
          position: 'relative',
          transition: 'transform 0.2s ease',
          transform: showOptions ? 'scale(0.98)' : 'scale(1)'
        }}>
          {/* Image Message */}
          {msg.message_type === 'image' && fileUrl ? (
            <div style={{ maxWidth: '300px' }}>
              <img 
                src={fileUrl} 
                alt={msg.file_name}
                style={{
                  maxWidth: '100%',
                  maxHeight: '260px',
                  borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                  cursor: 'pointer',
                  display: 'block'
                }}
                onClick={() => window.open(fileUrl, '_blank')}
                onError={e => e.target.style.display = 'none'}
              />
            </div>
          ) : msg.message_type === 'audio' && fileUrl ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: DESIGN_SYSTEM.spacing.sm }}>
              <audio controls style={{ height: '34px', maxWidth: '240px' }}>
                <source src={fileUrl} />
              </audio>
            </div>
          ) : fileUrl ? (
            <a 
              href={fileUrl} 
              download={msg.file_name} 
              style={{ textDecoration: 'none' }}
              onClick={e => e.stopPropagation()}
            >
              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: DESIGN_SYSTEM.spacing.sm,
                padding: DESIGN_SYSTEM.spacing.sm,
                background: DESIGN_SYSTEM.colors.secondary,
                border: `1px solid ${DESIGN_SYSTEM.colors.border}`,
                borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                cursor: 'pointer',
                maxWidth: '300px',
                transition: 'all 0.2s ease'
              }}
                onMouseEnter={e => {
                  e.currentTarget.style.borderColor = DESIGN_SYSTEM.colors.primary;
                  e.currentTarget.style.transform = 'translateY(-1px)';
                  e.currentTarget.style.boxShadow = DESIGN_SYSTEM.shadows.md;
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.borderColor = DESIGN_SYSTEM.colors.border;
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = DESIGN_SYSTEM.shadows.sm;
                }}
              >
                <span style={{ fontSize: '24px' }}>{getFileIcon(msg.mime_type)}</span>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{
                    fontSize: '13px',
                    fontWeight: '600',
                    color: DESIGN_SYSTEM.colors.text,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}>
                    {msg.file_name}
                  </div>
                  <div style={{
                    fontSize: '11px',
                    color: DESIGN_SYSTEM.colors.textSecondary,
                    marginTop: '2px'
                  }}>
                    {formatFileSize(msg.file_size)} · Click to download
                  </div>
                </div>
                <span style={{ fontSize: '18px', color: DESIGN_SYSTEM.colors.primary }}>⬇</span>
              </div>
            </a>
          ) : (
            <div style={{
              color: isOwn ? DESIGN_SYSTEM.colors.text : DESIGN_SYSTEM.colors.text,
              fontSize: '14px',
              lineHeight: '1.4',
              wordBreak: 'break-word'
            }}>
              {msg.is_deleted ? (
                <em style={{ opacity: 0.6 }}>Message deleted</em>
              ) : (
                renderContentWithMentions(msg.content)
              )}
            </div>
          )}
        </div>

        {/* Message Reactions */}
        <MessageReactions reactions={localReactions} isOwn={isOwn} />

        {/* Task Reference */}
        {msg.task_ref && msg.message_type !== 'task_notification' && (
          <div style={{ marginTop: DESIGN_SYSTEM.spacing.xs }}>
            <TaskPill taskRef={msg.task_ref} onTaskClick={onTaskClick} />
          </div>
        )}

        {/* Message Time and Options */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: DESIGN_SYSTEM.spacing.xs,
          marginTop: DESIGN_SYSTEM.spacing.xs,
          fontSize: '11px',
          color: DESIGN_SYSTEM.colors.textSecondary,
          paddingLeft: isOwn ? 0 : DESIGN_SYSTEM.spacing.xs
        }}>
          <span>{formatTime(msg.sent_at)}</span>
          {isOwn && (
            <span style={{ color: DESIGN_SYSTEM.colors.success, marginLeft: DESIGN_SYSTEM.spacing.xs }}>
              ✓✓
            </span>
          )}
          <button
            onClick={() => setShowOptions(!showOptions)}
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              padding: DESIGN_SYSTEM.spacing.xs,
              fontSize: '12px',
              color: DESIGN_SYSTEM.colors.textSecondary,
              borderRadius: DESIGN_SYSTEM.borderRadius.sm,
              transition: 'background 0.2s ease',
              opacity: 0.7
            }}
            onMouseEnter={e => {
              e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary;
              e.currentTarget.style.opacity = '1';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = 'none';
              e.currentTarget.style.opacity = '0.7';
            }}
          >
            ⋮
          </button>
        </div>

        {/* Message Options Menu */}
        {showOptions && (
          <MessageOptionsMenu
            msg={msg}
            isOwn={isOwn}
            onClose={() => setShowOptions(false)}
            onCopy={handleCopy}
            onForward={handleForward}
            onReact={handleReact}
            onDelete={handleDelete}
          />
        )}
      </div>
    </div>
  );
}

/* ── Professional Mention Dropdown Component ───────────────────────────── */
function MentionDropdown({ users, query, selectedIndex, onSelect, onUserSelect, onClose }) {
  if (!users.length) return null;

  return (
    <div 
      style={{
        position: 'absolute',
        bottom: '100%',
        left: 0,
        right: 0,
        background: DESIGN_SYSTEM.colors.surface,
        border: `1px solid ${DESIGN_SYSTEM.colors.border}`,
        borderRadius: DESIGN_SYSTEM.borderRadius.md,
        maxHeight: '200px',
        overflowY: 'auto',
        zIndex: 1000,
        marginBottom: DESIGN_SYSTEM.spacing.sm,
        boxShadow: DESIGN_SYSTEM.shadows.lg
      }}
    >
      {users.map((user, index) => (
        <div
          key={user.id}
          style={{
            padding: DESIGN_SYSTEM.spacing.sm,
            cursor: 'pointer',
            background: index === selectedIndex ? DESIGN_SYSTEM.colors.primaryLight : 'transparent',
            display: 'flex',
            alignItems: 'center',
            gap: DESIGN_SYSTEM.spacing.sm,
            transition: 'background 0.2s ease',
            borderBottom: index < users.length - 1 ? `1px solid ${DESIGN_SYSTEM.colors.border}` : 'none'
          }}
          onClick={() => onUserSelect(user)}
          onMouseEnter={() => onSelect(index)}
        >
          <div style={{
            width: '36px',
            height: '36px',
            borderRadius: DESIGN_SYSTEM.borderRadius.full,
            background: getAvatarColor(user.full_name),
            color: '#ffffff',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '12px',
            fontWeight: '700',
            boxShadow: DESIGN_SYSTEM.shadows.sm
          }}>
            {getInitials(user.full_name)}
          </div>
          <div>
            <div style={{ 
              fontSize: '13px', 
              fontWeight: '600',
              color: DESIGN_SYSTEM.colors.text 
            }}>
              {user.full_name}
            </div>
            <div style={{ 
              fontSize: '11px', 
              color: DESIGN_SYSTEM.colors.textSecondary 
            }}>
              {user.role}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

/* ── Professional Message Options Menu ───────────────────────────── */
function MessageOptionsMenu({ msg, isOwn, onClose, onCopy, onForward, onReact, onDelete }) {
  const [showReactions, setShowReactions] = useState(false);

  const reactions = ['❤️', '😂', '😮', '😢', '😡', '👍', '👎', '🎉'];

  return (
    <div style={{
      position: 'absolute',
      bottom: '100%',
      left: isOwn ? 'auto' : 0,
      right: isOwn ? 0 : 'auto',
      background: DESIGN_SYSTEM.colors.surface,
      border: `1px solid ${DESIGN_SYSTEM.colors.border}`,
      borderRadius: DESIGN_SYSTEM.borderRadius.md,
      boxShadow: DESIGN_SYSTEM.shadows.lg,
      zIndex: 1000,
      minWidth: '160px',
      marginBottom: DESIGN_SYSTEM.spacing.sm,
      overflow: 'hidden'
    }}>
      <div style={{ padding: 0 }}>
        <button
          onClick={() => { onCopy(); onClose(); }}
          style={{
            width: '100%',
            padding: `${DESIGN_SYSTEM.spacing.sm} ${DESIGN_SYSTEM.spacing.md}`,
            border: 'none',
            background: 'transparent',
            textAlign: 'left',
            cursor: 'pointer',
            fontSize: '13px',
            color: DESIGN_SYSTEM.colors.text,
            display: 'flex',
            alignItems: 'center',
            gap: DESIGN_SYSTEM.spacing.sm,
            transition: 'background 0.2s ease'
          }}
          onMouseEnter={e => e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary}
          onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
        >
          <span style={{ fontSize: '16px' }}>📋</span>
          Copy
        </button>

        <button
          onClick={() => { onForward(); onClose(); }}
          style={{
            width: '100%',
            padding: `${DESIGN_SYSTEM.spacing.sm} ${DESIGN_SYSTEM.spacing.md}`,
            border: 'none',
            background: 'transparent',
            textAlign: 'left',
            cursor: 'pointer',
            fontSize: '13px',
            color: DESIGN_SYSTEM.colors.text,
            display: 'flex',
