        {isOwn && (
          <button
            onClick={() => { onDelete(); onClose(); }}
            style={{
              width: '100%',
              padding: `${DESIGN_SYSTEM.spacing.sm} ${DESIGN_SYSTEM.spacing.md}`,
              border: 'none',
              background: 'transparent',
              textAlign: 'left',
              cursor: 'pointer',
              fontSize: '13px',
              color: DESIGN_SYSTEM.colors.danger,
              display: 'flex',
              alignItems: 'center',
              gap: DESIGN_SYSTEM.spacing.sm,
              transition: 'background 0.2s ease'
            }}
