            background: `${DESIGN_SYSTEM.colors.danger}15`,
            border: `1px solid ${DESIGN_SYSTEM.colors.danger}30`,
            borderRadius: DESIGN_SYSTEM.borderRadius.md
          }}>
            <span style={{
              fontSize: '13px',
              color: DESIGN_SYSTEM.colors.danger,
              fontWeight: '600'
            }}>
              🔴 Recording…
            </span>
            <button
              onClick={stopRec}
              style={{
                padding: `${DESIGN_SYSTEM.spacing.xs} ${DESIGN_SYSTEM.spacing.sm}`,
                background: DESIGN_SYSTEM.colors.danger,
                color: '#ffffff',
                border: 'none',
                borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                cursor: 'pointer',
                fontSize: '12px',
                fontWeight: '500'
              }}
            >
              Stop & Send
            </button>
          </div>
        ) : (
          <div style={{
            display: 'flex',
            alignItems: 'flex-end',
            gap: DESIGN_SYSTEM.spacing.sm,
            background: DESIGN_SYSTEM.colors.secondary,
            border: `1px solid ${DESIGN_SYSTEM.colors.border}`,
            borderRadius: DESIGN_SYSTEM.borderRadius.lg,
            padding: DESIGN_SYSTEM.spacing.sm,
            transition: 'border-color 0.2s ease'
          }}>
            {/* Message Input */}
            <textarea
              ref={textareaRef}
              value={inputText}
              onChange={onInput}
              onKeyDown={onKey}
              placeholder={`Message ${group.group_name}…`}
              rows={1}
              style={{
                flex: 1,
                border: 'none',
                background: 'transparent',
                resize: 'none',
                outline: 'none',
                fontSize: '14px',
                lineHeight: '1.4',
                color: DESIGN_SYSTEM.colors.text,
                minHeight: '20px',
                maxHeight: '120px',
                fontFamily: 'inherit'
              }}
              onInput={e => {
                e.target.style.height = 'auto';
                e.target.style.height = Math.min(e.target.scrollHeight, 120) + 'px';
              }}
            />

            {/* Input Actions */}
            <div style={{ display: 'flex', alignItems: 'center', gap: DESIGN_SYSTEM.spacing.xs }}>
              <input
                ref={fileRef}
                type="file"
                style={{ display: 'none' }}
                onChange={uploadFile}
                accept="image/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.zip"
              />

              {/* Task Button */}
              <button
                onClick={() => setShowTaskPopup(p => !p)}
                title="Create task"
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  padding: DESIGN_SYSTEM.spacing.sm,
                  color: showTaskPopup ? DESIGN_SYSTEM.colors.primary : DESIGN_SYSTEM.colors.textSecondary,
                  borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                  transition: 'all 0.2s ease',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary;
                  e.currentTarget.style.color = DESIGN_SYSTEM.colors.primary;
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.background = 'none';
                  e.currentTarget.style.color = showTaskPopup ? DESIGN_SYSTEM.colors.primary : DESIGN_SYSTEM.colors.textSecondary;
                }}
              >
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M9 11l3 3L22 4"/>
                  <path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/>
                </svg>
              </button>

              {/* Upload Button */}
              <button
                onClick={() => fileRef.current?.click()}
                title="Attach file"
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  padding: DESIGN_SYSTEM.spacing.sm,
                  color: DESIGN_SYSTEM.colors.textSecondary,
                  borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                  transition: 'all 0.2s ease',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary;
                  e.currentTarget.style.color = DESIGN_SYSTEM.colors.primary;
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.background = 'none';
                  e.currentTarget.style.color = DESIGN_SYSTEM.colors.textSecondary;
                }}
              >
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/>
                </svg>
              </button>

              {/* Voice Record Button */}
              <button
                onMouseDown={startRec}
                onTouchStart={startRec}
                title="Record voice"
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  padding: DESIGN_SYSTEM.spacing.sm,
                  color: DESIGN_SYSTEM.colors.textSecondary,
                  borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                  transition: 'all 0.2s ease',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary;
                  e.currentTarget.style.color = DESIGN_SYSTEM.colors.primary;
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.background = 'none';
                  e.currentTarget.style.color = DESIGN_SYSTEM.colors.textSecondary;
                }}
              >
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z"/>
                  <path d="M19 10v2a7 7 0 01-14 0v-2"/>
                  <line x1="12" y1="19" x2="12" y2="23"/>
                  <line x1="8" y1="23" x2="16" y2="23"/>
                </svg>
              </button>

              {/* Send Button */}
              <button
                onClick={send}
                disabled={sending || !inputText.trim()}
                title="Send message"
                style={{
                  background: sending || !inputText.trim() 
                    ? DESIGN_SYSTEM.colors.textSecondary 
                    : DESIGN_SYSTEM.colors.primary,
                  color: '#ffffff',
                  border: 'none',
                  borderRadius: DESIGN_SYSTEM.borderRadius.sm,
                  padding: `${DESIGN_SYSTEM.spacing.sm} ${DESIGN_SYSTEM.spacing.md}`,
                  cursor: sending || !inputText.trim() ? 'not-allowed' : 'pointer',
                  fontSize: '13px',
                  fontWeight: '500',
                  transition: 'all 0.2s ease',
                  display: 'flex',
                  alignItems: 'center',
                  gap: DESIGN_SYSTEM.spacing.xs,
                  opacity: sending || !inputText.trim() ? 0.6 : 1
                }}
                onMouseEnter={e => {
                  if (!sending && inputText.trim()) {
                    e.currentTarget.style.background = DESIGN_SYSTEM.colors.primaryDark;
                  }
                }}
                onMouseLeave={e => {
                  if (!sending && inputText.trim()) {
                    e.currentTarget.style.background = DESIGN_SYSTEM.colors.primary;
                  }
                }}
              >
                {sending ? (
                  <div style={{
                    width: '14px',
                    height: '14px',
                    border: '2px solid #ffffff',
                    borderTop: '2px solid transparent',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite'
                  }}></div>
                ) : (
                  <>
                    Send
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <line x1="22" y1="2" x2="11" y2="13"/>
                      <polygon points="22 2 15 22 11 13 2 9 22 2"/>
                    </svg>
                  </>
                )}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Close main container div */}
      </div>
    </>
  );
}
